        try:
            header = json.loads(_base64url_decode(header_b64))
        except (json.JSONDecodeError, Exception) as e:
            raise InvalidTokenError(f"Invalid token header: {e}")

        # Validate algorithm
        token_algorithm = header.get('alg')
        if not token_algorithm:
            raise InvalidTokenError("Token header missing 'alg' field")

        if token_algorithm not in algorithms:
            raise UnsupportedAlgorithmError(
                f"Algorithm '{token_algorithm}' is not in the allowed list: {algorithms}"
            )

        if token_algorithm not in ALGORITHMS:
            raise UnsupportedAlgorithmError(f"Unsupported algorithm: {token_algorithm}")

        # SECURITY: Reject 'none' algorithm
        if token_algorithm.lower() == 'none':
            raise UnsupportedAlgorithmError("Algorithm 'none' is not allowed")

        # SECURITY: Prevent algorithm confusion attacks
        # If only HMAC algorithms are configured but token claims RSA (or vice versa),
        # this could be an attack
        if key is None:
            key = self._get_key_for_algorithm(token_algorithm, for_signing=False)

