        try:
            signature = _base64url_decode(signature_b64)
        except Exception as e:
            raise InvalidTokenError(f"Invalid signature encoding: {e}")

        alg_impl = ALGORITHMS[token_algorithm]
        if not alg_impl.verify(signing_input, signature, key):
            raise InvalidTokenError("Invalid token signature")

        # Decode payload
        try:
            payload = json.loads(_base64url_decode(payload_b64))
        except (json.JSONDecodeError, Exception) as e:
            raise InvalidTokenError(f"Invalid token payload: {e}")

        if not isinstance(payload, dict):
            raise InvalidTokenError("Token payload must be a JSON object")

        # Verify expiration
        if verify_exp and 'exp' in payload:
            now = int(time.time())
            if now > payload['exp'] + self._leeway:
                raise TokenExpiredError("Token has expired")

        # Verify not-before
        if 'nbf' in payload:
            now = int(time.time())
            if now < payload['nbf'] - self._leeway:
                raise InvalidTokenError("Token is not yet valid (nbf claim)")

