    def get_token_from_request(self) -> Optional[str]:
        """Extract JWT token from the current Flask request."""
        if self._token_location == 'header':
            auth_header = request.headers.get(self._header_name, '')
            if not auth_header:
                return None
            parts = auth_header.split()
            if len(parts) == 2 and parts[0] == self._header_prefix:
                return parts[1]
            elif len(parts) == 1:
                return parts[0]
            return None
        elif self._token_location == 'query':
            return request.args.get('token')
        elif self._token_location == 'cookie':
            return request.cookies.get('access_token')
        return None

    def jwt_required(self, fn=None, algorithms=None, required_claims=None):
        """
        Decorator to protect routes with JWT authentication.
        
        Can be used as @jwt_required or @jwt_required(algorithms=['RS256'])
        """
